  if(!state.classSubjects.length){ state.classSubjects.push({id:'M1',classId:'C1',subjectId:'S1'},{id:'M2',classId:'C1',subjectId:'S2'},{id:'M3',classId:'C2',subjectId:'S1'},{id:'M4',classId:'C2',subjectId:'S3'}); }
  if(!state.assessments.length){ state.assessments.push({id:'A1',name:'CAT 1',outOf:30},{id:'A2',name:'Exam',outOf:70}); }
